sql:
SELECT COUNT(*) 
FROM normalization_history 
WHERE normalized_status = 'Normalized';

SELECT mutation_type
FROM gene_mutations
WHERE gene_id = 1;

SELECT COUNT(*) 
FROM gene_mutations 
WHERE mutation_type = 'deletion';

SELECT role_type, COUNT(role_id) AS role_count, MAX(citation_count) AS max_citation_count
FROM gene_cancer_roles
GROUP BY role_type;

SELECT cancer_normalized, description
FROM cancers
WHERE cancer_id = 0;

SELECT gene_id, cancer_id
FROM gene_cancer_roles
WHERE role_type = 'Oncogene';

external_knowledge:
- This query assumes that the role count represents the number of different roles a gene plays in various cancers; 
- The normalization status represents the current state of the gene-cancer relationship data; 
- A higher role count indicates a gene's greater involvement in various cancers.

